TC_CREDIT_REVOKED,AM00_STATC_CRVK_ADD_DATE AS STATC_CRVK_ADD_DATE,AM00_STATC_CRVK_MNT_DATE AS STATC_CRVK_MNT_DATE,AM00_STATC_CURRENT_PAST_DUE AS STATC_CURRENT_PAST_DUE,AM00_STATC_FIRST_USE AS STATC_FIRST_USE,AM00_STATC_FIXED_PAYMENT AS STATC_FIXED_PAYMENT,AM00_STATC_RETURN_MAIL AS STATC_RETURN_MAIL,AM00_STATC_SECURITY_FRAUD AS STATC_SECURITY_FRAUD,AM00_STATC_TIERED_AUTH AS STATC_TIERED_AUTH,AM00_STATC_WATCH AS STATC_WATCH,AM00_STATF_ACTIVE_THIS_CYCLE AS STATF_ACTIVE_THIS_CYCLE,AM00_STATF_ACTIVE_THIS_MONTH AS STATF_ACTIVE_THIS_MONTH,AM00_STATF_ACTIVE_THIS_YEAR AS STATF_ACTIVE_THIS_YEAR,AM00_STATF_ADDR_CHNG_THIS_CYC AS STATF_ADDR_CHNG_THIS_CYC,AM00_STATF_CASH_REV_THIS_CYC AS STATF_CASH_REV_THIS_CYC,AM00_STATF_FRAUD AS STATF_FRAUD,AM00_STATF_INACTIVE AS STATF_INACTIVE,AM00_STATF_INACTIVE_DATE AS STATF_INACTIVE_DATE,AM00_TNDM_AUTH_PROC_TIER_EDATE AS TNDM_AUTH_PROC_TIER_EDATE,AM00_TNDM_AUTH_PROC_TIER_SDATE AS TNDM_AUTH_PROC_TIER_SDATE,AM00_TRIAD_SCORE_ALIGNED AS TRIAD_SCORE_ALIGNED,AM00_TRIAD_SCORE_CARD_ID AS TRIAD_SCORE_CARD_ID,AM00_TSYS_PRODUCT_CODE AS TSYS_PRODUCT_CODE,AM00_TYPEC_VIP AS TYPEC_VIP, FILE_CREATE_DT as AM00_FILE_CREATE_DT
