CREASE_YTD,AM02_NUM_LIMIT_INCREASE_LTD AS NUM_LIMIT_INCREASE_LTD,AM02_NUM_LIMIT_INCREASE_PYE AS NUM_LIMIT_INCREASE_PYE,AM02_NUM_LIMIT_INCREASE_YTD AS NUM_LIMIT_INCREASE_YTD,AM02_NUM_NSF_PAYMENTS_CTD AS NUM_NSF_PAYMENTS_CTD,AM02_NUM_NSF_PAYMENTS_PYE AS NUM_NSF_PAYMENTS_PYE,AM02_NUM_NSF_PAYMENTS_YTD AS NUM_NSF_PAYMENTS_YTD,AM02_NUM_PAYMENTS_CTD AS NUM_PAYMENTS_CTD,AM02_NUM_PAYMENTS_LTD AS NUM_PAYMENTS_LTD,AM02_NUM_PAYMENTS_PYE AS NUM_PAYMENTS_PYE,AM02_NUM_PAYMENTS_YTD AS NUM_PAYMENTS_YTD,AM02_NUM_PURCHASES_LTD AS NUM_PURCHASES_LTD,AM02_NUM_PURCHASES_YTD AS NUM_PURCHASES_YTD,AM02_PAID_IN_FULL_CYCLE_IND AS PAID_IN_FULL_CYCLE_IND,AM02_PASTDUE_AT_CYCLE_1 AS PASTDUE_AT_CYCLE_1,AM02_PASTDUE_AT_CYCLE_10 AS PASTDUE_AT_CYCLE_10,AM02_PASTDUE_AT_CYCLE_11 AS PASTDUE_AT_CYCLE_11,AM02_PASTDUE_AT_CYCLE_12 AS PASTDUE_AT_CYCLE_12,AM02_PASTDUE_AT_CYCLE_2 AS PASTDUE_AT_CYCLE_2,AM02_PASTDUE_AT_CYCLE_3 AS PASTDUE_AT_CYCLE_3,AM02_PASTDUE_AT_CYCLE_4 AS PASTDUE_AT_CYCLE_4,AM02_PASTDUE_AT_CYCLE_5 AS PASTDUE_AT_CYCLE_5,AM02_PASTDUE_AT_CYCLE_6 AS PASTDUE_AT_CYCLE_6,AM02_PASTDUE_AT_CYCLE_7 AS PASTDUE_AT_CYCLE_7,AM02_PASTDUE_AT_CYCLE_8 AS PASTDUE_AT_CYCLE_8,AM02_PASTDUE_AT_CYCLE_9 AS PASTDUE_AT_CYCLE_9
