CREATE OR REPLACE VIEW
       `pcb-{env}-processing.domain_scoring.AH01_VIEW`
    OPTIONS (
        expiration_timestamp = TIMESTAMP_ADD(CURRENT_TIMESTAMP(), INTERVAL 6 HOUR),
        description = "View for AH01 segment"
    ) AS
       SELECT * EXCEPT(LATEST_CYCLED_RECORD_RN) FROM (
       SELECT MAST_ACCOUNT_ID as AH01_MAST_ACCOUNT_ID, AH01_ACTUAL_APR as ACTUAL_APR, AH01_AMT_NSF_PAYMENTS AS AMT_NSF_PAYMENTS, AH01_AMT_OVERLIMIT AS AMT_OVERLIMIT, AH01_AMT_PASTDUE_1 AS AMT_PASTDUE_1,AH01_AMT_PASTDUE_2 AS AMT_PASTDUE_2,AH01_AMT_PASTDUE_3 AS AMT_PASTDUE_3,AH01_AMT_PASTDUE_4 AS AMT_PASTDUE_4,AH01_AMT_PASTDUE_5 AS AMT_PASTDUE_5,AH01_AMT_PASTDUE_6 AS AMT_PASTDUE_6,AH01_AMT_PASTDUE_7 AS AMT_PASTDUE_7,AH01_AMT_PASTDUE_8 AS AMT_PASTDUE_8,AH01_AMT_PASTDUE_9 AS AMT_PASTDUE_9,AH01_AMT_PASTDUE_10 AS AMT_PASTDUE_10,AH01_AMT_PASTDUE_11 AS AMT_PASTDUE_11,AH01_AMT_PASTDUE_12 AS AMT_PASTDUE_12,AH01_AMT_PAYMENTS AS AMT_PAYMENTS,AH01_BALANCE_CURRENT AS BALANCE_CURRENT_AH,AH01_BALANCE_PREV_STATEMENT AS BALANCE_PREV_STATEMENT_AH,AH01_NUM_PAYMENTS AS NUM_PAYMENTS, AH01_DATE_HIGH_OL_CTD AS DATE_HIGH_OL_CTD, AH01_NUM_OVERLIMIT AS NUM_OVERLIMIT, IFNULL(AH01_CHARGEOFF,"") AS CHARGEOFF, AH01_LIMIT_CREDIT AS LIMIT_CREDIT, AH01_WEIGHTED_AVG_APR AS WEIGHTED_AVG_APR, IFNULL(AH01_PAST_DUE_REAGE,"") AS PAST_DUE_REAGE,
       dense_rank() OVER(PARTITION BY MAST_ACCOUNT_ID ORDER BY FILE_CREATE_DT desc, AH01_CDATE_CYCLE desc) as LATEST_CYCLED_RECORD_RN
       FROM pcb-{env}-curated.domain_account_management.AH01
       WHERE FILE_CREATE_DT BETWEEN DATE_SUB('{ah_file_create_date}', INTERVAL 1 MONTH) AND '{ah_file_create_date}'
       AND AH00_APPLICATION_SUFFIX = 0) where LATEST_CYCLED_RECORD_RN =1 ;


   CREATE OR REPLACE VIEW
        `pcb-{env}-processing.domain_scoring.AH02_REAGE_VIEW`
       OPTIONS (
          expiration_timestamp = TIMESTAMP_ADD(CURRENT_TIMESTAMP(), INTERVAL 6 HOUR),
          description = "View for AH02_REAGE segment"
       ) AS
           SELECT * EXCEPT(LATEST_CYCLED_RECORD_RN) FROM (
        SELECT MAST_ACCOUNT_ID as AH02_REAGE_MAST_ACCOUNT_ID, AH02_DATE_AUTO_PASTDUE_REAGE AS DATE_AUTO_PASTDUE_REAGE,AH02_DATE_MAN_PASTDUE_REAGE AS DATE_MAN_PASTDUE_REAGE,AH02_NUM_AUTO_PD_REAGE_LTD AS NUM_AUTO_PD_REAGE_LTD,
        dense_rank() OVER(PARTITION BY MAST_ACCOUNT_ID ORDER BY FILE_CREATE_DT desc, AH02_CDATE_HISTORY desc) as LATEST_CYCLED_RECORD_RN
        FROM pcb-{env}-curated.domain_account_management.AH02_REAGE
        WHERE FILE_CREATE_DT BETWEEN DATE_SUB('{ah_file_create_date}', INTERVAL 1 MONTH) AND '{ah_file_create_date}'
        AND AH00_APPLICATION_SUFFIX = 0) where LATEST_CYCLED_RECORD_RN =1 ;

